mapper.select:
/* PtnrAddSvcMapper.ptnrAddSvcList */ SELECT RAT.RATE_CD , RAT.RATE_NM , PADD.PARTNER_ID AS PTNR_ID , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0243' AND USG_YN = 'Y' AND CD_VAL = PADD.PARTNER_ID) AS PTNR_NM , ARAT.RATE_CD AS ADD_SVC_CD , ARAT.RATE_NM AS ADD_SVC_NM , PADD.DC_CD , FN_GET_CODENM('MSP00016', PADD.DC_CD) AS DC_CD_NM , ARAT.BASE_AMT , PADD.POINT_VAL , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0242' AND USG_YN = 'Y' AND CD_VAL = PADD.USE_YN) AS USE_YN , TO_CHAR(TO_DATE(PADD.STRT_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS STRT_DATE , TO_CHAR(TO_DATE(PADD.END_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS END_DATE , FN_GET_USRNM(PADD.RVISN_ID) AS USR_NM FROM MSP_RATE_MST RAT , MSP_RATE_MST ARAT , MSP_PARTNER_ADD_SVC_MST PADD WHERE RAT.PAY_CL_CD = 'PO' AND RAT.SERVICE_TYPE = 'P' AND ARAT.SERVICE_TYPE = 'R' AND PADD.RATE_CD = RAT.RATE_CD AND PADD.ADD_SVC_CD = ARAT.RATE_CD
AND PADD.PARTNER_ID = #{ptnrId, jdbcType=VARCHAR}
AND RAT.RATE_NM LIKE '%'||#{rateNm, jdbcType=VARCHAR}||'%'
AND ARAT.RATE_NM LIKE '%'||#{addSvcNm, jdbcType=VARCHAR}||'%'
AND PADD.USE_YN = #{useYn, jdbcType=VARCHAR}
ORDER BY RAT.RATE_NM DESC, ARAT.RATE_NM DESC, PADD.STRT_DATE DESC

