(
	#{ptnrId, jdbcType=VARCHAR}
  , #{rateCd, jdbcType=VARCHAR}
  , #{addSvcCd, jdbcType=VARCHAR}
  , #{dcCd, jdbcType=VARCHAR}
  , #{pointVal, jdbcType=VARCHAR}
  , #{useYn, jdbcType=VARCHAR}
  , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
  , '99991231235959'
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
)

mapper.update:
/* PtnrAddSvcMapper.ptnrAddSvcUpdate */
UPDATE  MSP_PARTNER_ADD_SVC_MST
   SET  STRT_DATE = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
      , DC_CD = #{dcCd, jdbcType=VARCHAR}
      , POINT_VAL = #{pointVal, jdbcType=VARCHAR}
      , USE_YN = #{useYn, jdbcType=VARCHAR}
      , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
      , RVISN_DTTM = SYSDATE
 WHERE  PARTNER_ID = #{ptnrId, jdbcType=VARCHAR}
   AND  RATE_CD = #{rateCd, jdbcType=VARCHAR}
   AND  ADD_SVC_CD = #{addSvcCd, jdbcType=VARCHAR}

